import { processRefund, RefundResult } from "./processRefund";

// ─── AC1: Credit card refunds have no fee ─────────────────────────────────────

describe("AC1 – credit card refunds carry no fee", () => {
  it("returns fee=0 and refundAmount equal to the full amount for credit_card", () => {
    const result: RefundResult = processRefund("order-001", 100, "credit_card");

    expect(result.fee).toBe(0);
    expect(result.refundAmount).toBe(100);
  });

  it("result shape is correct for a credit card refund", () => {
    const result = processRefund("order-002", 250, "credit_card");

    expect(result).toEqual({
      orderId: "order-002",
      refundAmount: 250,
      status: "approved",
      fee: 0,
    });
  });
});

// ─── AC2: Bank transfer refunds have a 1.50 fee deducted ─────────────────────

describe("AC2 – bank transfer refunds deduct a 1.50 fee", () => {
  it("returns fee=1.5 and refundAmount = amount - 1.5 for bank_transfer", () => {
    const result: RefundResult = processRefund("order-003", 100, "bank_transfer");

    expect(result.fee).toBe(1.5);
    expect(result.refundAmount).toBe(98.5);
  });

  it("result shape is correct for a bank transfer refund", () => {
    const result = processRefund("order-004", 50, "bank_transfer");

    expect(result).toEqual({
      orderId: "order-004",
      refundAmount: 48.5,
      status: "approved",
      fee: 1.5,
    });
  });
});

// ─── AC3: Empty orderId throws validation error ───────────────────────────────

describe("AC3 – empty orderId throws a validation error", () => {
  it("throws when orderId is an empty string", () => {
    expect(() => processRefund("", 100, "credit_card")).toThrow(
      "orderId is required"
    );
  });

  it("thrown value is an Error instance", () => {
    expect(() => processRefund("", 100, "credit_card")).toThrow(Error);
  });
});

// ─── AC4: Amount of 0 throws validation error ────────────────────────────────

describe("AC4 – amount of 0 throws a validation error", () => {
  it("throws when amount is exactly 0", () => {
    expect(() => processRefund("order-005", 0, "credit_card")).toThrow(
      "amount must be positive"
    );
  });

  it("throws when amount is negative (amount <= 0 guard)", () => {
    expect(() => processRefund("order-006", -1, "credit_card")).toThrow(
      "amount must be positive"
    );
  });
});

// ─── AC5: Amount of 10001 throws validation error ────────────────────────────

describe("AC5 – amount of 10001 exceeds the maximum and throws", () => {
  it("throws when amount is 10001", () => {
    expect(() => processRefund("order-007", 10001, "credit_card")).toThrow(
      "amount exceeds maximum refund limit"
    );
  });

  it("throws when amount is well above the limit", () => {
    expect(() => processRefund("order-008", 99999, "bank_transfer")).toThrow(
      "amount exceeds maximum refund limit"
    );
  });
});

// ─── AC6: Amount of 10000 is valid (boundary — should succeed) ───────────────

describe("AC6 – amount of 10000 is at the boundary and must succeed", () => {
  it("does not throw for amount=10000 (credit_card)", () => {
    expect(() =>
      processRefund("order-009", 10000, "credit_card")
    ).not.toThrow();
  });

  it("returns status=approved and correct amounts for the boundary value", () => {
    const result = processRefund("order-010", 10000, "credit_card");

    expect(result.status).toBe("approved");
    expect(result.refundAmount).toBe(10000);
    expect(result.fee).toBe(0);
  });

  it("boundary also works for bank_transfer (fee still deducted)", () => {
    const result = processRefund("order-011", 10000, "bank_transfer");

    expect(result.status).toBe("approved");
    expect(result.refundAmount).toBe(9998.5);
    expect(result.fee).toBe(1.5);
  });
});

// ─── AC7: Whitespace-only orderId throws validation error ────────────────────

describe('AC7 – whitespace-only orderId (e.g., "   ") throws a validation error', () => {
  it('throws for orderId="   " (three spaces)', () => {
    expect(() => processRefund("   ", 100, "credit_card")).toThrow(
      "orderId is required"
    );
  });

  it('throws for orderId="\\t\\n" (tab and newline only)', () => {
    expect(() => processRefund("\t\n", 100, "credit_card")).toThrow(
      "orderId is required"
    );
  });

  it('throws for orderId=" " (single space)', () => {
    expect(() => processRefund(" ", 100, "credit_card")).toThrow(
      "orderId is required"
    );
  });
});

